def extended_gcd_iterative(a, b):
    # On initialise nos coefficients comme dans un tableau de substitution
    u0, u1 = 1, 0
    v0, v1 = 0, 1
    
    while b != 0:
        # 1. On fait la division entière (quotient q et reste r)
        q = a // b
        a, b = b, a % b # Le fameux décalage "et ainsi de suite"
        
        # 2. On met à jour les coefficients u et v par substitution
        u0, u1 = u1, u0 - q * u1
        v0, v1 = v1, v0 - q * v1
        
    return a, u0, v0

