#!/usr/bin/env python3

def tonelli_shanks(a, p):
    # Étape 1 : On vérifie si a est bien un carré parfait (Symbole de Legendre)
    if pow(a, (p - 1) // 2, p) != 1:
        return None

    # Étape 2 : On écrit p - 1 sous la forme Q * 2^S
    s = 0
    q = p - 1
    while q % 2 == 0:
        s += 1
        q //= 2

    # Étape 3 : On cherche un non-résidu quadratique 'z'
    z = 2
    while pow(z, (p - 1) // 2, p) != p - 1:
        z += 1

    # Étape 4 : Initialisation des variables de l'algorithme
    m = s
    c = pow(z, q, p)
    t = pow(a, q, p)
    r = pow(a, (q + 1) // 2, p)

    # Étape 5 : Boucle principale de Tonelli-Shanks
    while True:
        if t == 0: return 0
        if t == 1: return r
        
        # On cherche le plus petit 'i' tel que t^(2^i) = 1 mod p
        i = 0
        curr = t
        while curr != 1:
            i += 1
            curr = pow(curr, 2, p)
            if i == m:
                return None

        # Mise à jour des constantes
        b = pow(c, 1 << (m - i - 1), p)
        m = i
        c = pow(b, 2, p)
        t = (t * c) % p
        r = (r * b) % p


