# Données du problème CryptoHack
a = [2, 3, 5]
n = [5, 11, 17]

# 1. Calcul du produit global N
N = 1
for mod in n:
    N *= mod

# 2. Application de la formule du CRT
x = 0
for a_i, n_i in zip(a, n):
    N_i = N // n_i
    # Calcul de l'inverse modulaire de N_i modulo n_i
    M_i = pow(N_i, -1, n_i)
    x += a_i * N_i * M_i

# Résultat final modulo N
flag = x % N
print(f"Le flag est : {flag}")